// Generate markdown filename and path
const item = $json;
const dateTime = new Date(item.published_date);
const dateStr = dateTime.toISOString().split('T')[0];
const timeStr = dateTime.toISOString().split('T')[1].substring(0, 5).replace(':', '-');
const slug = item.title
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .substring(0, 40);

const filename = `${dateStr}-${timeStr}-${slug}.md`;
const filepath = `/Intelligence/Sources/${item.source_tier}/${filename}`;

return { ...item, filename, filepath };

// Generate markdown frontmatter and content
const item = $json;

const frontmatter = `---
title: "${item.title.replace(/"/g, '\\"')}"
source: "${item.source}"
source_tier: ${item.source_tier}
date: ${item.published_date}
url: "${item.link}"
tags:
  - intelligence
  - tier-${item.source_tier}
score: ${item.combinedScore}
relevance: ${item.relevanceScore}
routing: ${item.routing_decision}
---
`;

const body = `## Summary
${item.summary}

## Key Details
- **Source**: [${item.source}](${item.link})
- **Published**: ${new Date(item.published_date).toLocaleString()}
- **Relevance Score**: ${item.relevanceScore}/100
- **Novelty Score**: ${item.noveltyScore}/100  
- **Quality Score**: ${item.qualityScore}/100
- **Combined Score**: ${item.combinedScore}/100
- **Routing Decision**: ${item.routing_decision}

## Full Content
${item.body || item.summary}

## Related
- #intelligence-briefing
- #tier-${item.source_tier}
`;

const markdown = frontmatter + body;

return { ...item, markdown, frontmatter };

